/* ================================================= */
/* LIGHT MODE — WHITE BACKGROUND */
/* ================================================= */

:root {
  --bg-main: #ffffff;

  /* GLASS (LIGHT) */
  --glass-bg-strong: rgba(255, 255, 255, 0.75);
  --glass-bg-soft: rgba(255, 255, 255, 0.45);
  --glass-border: rgba(17, 24, 39, 0.08);
  --glass-shadow: 0 8px 24px rgba(17, 24, 39, 0.12);
  --glass-blur: blur(10px);

  /* TEXT */
  --text-main: #111827;
  --text-muted: #6b7280;

  /* ACCENTS */
  --accent-blue: #7c5cff;
  --accent-green: #22c55e;
  --accent-amber: #f59e0b;
  --accent-red: #ef4444;
}



/* ================================================= */
/* TEXT CARD — GLASS BASE */
/* ================================================= */

.nrdb-ui-widget.nrdb-ui-text {
  background: linear-gradient(
    135deg,
    var(--glass-bg-strong),
    var(--glass-bg-soft)
  );

  backdrop-filter: var(--glass-blur);
  -webkit-backdrop-filter: var(--glass-blur);

  border-radius: clamp(14px, 2vw, 18px);
  padding: clamp(10px, 2.5vw, 14px);

  border: 1px solid var(--glass-border);
  box-shadow: var(--glass-shadow);
}

/* ================================================= */
/* INNER LAYOUT */
/* ================================================= */

.nrdb-ui-text > .nrdb-ui-text {
  display: flex !important;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  height: 100%;
  text-align: center;
  font-family: "Inter", "Segoe UI", Roboto, sans-serif !important;
}

/* ================================================= */
/* TITLE */
/* ================================================= */

.nrdb-ui-text-label {
  font-size: clamp(0.7rem, 1.8vw, 0.85rem) !important;
  font-weight: 600 !important;
  letter-spacing: 0.14em !important;
  text-transform: uppercase;
  color: var(--text-muted) !important;
  margin-bottom: clamp(4px, 1.5vw, 8px) !important;
}

/* ================================================= */
/* VALUE */
/* ================================================= */

.nrdb-ui-text-value {
  font-size: clamp(1.4rem, 5vw, 2.3rem) !important;
  font-weight: 600;
  line-height: 1.1;
  color: var(--text-main) !important;

  /* subtle clarity on white */
  text-shadow: 0 1px 0 rgba(255, 255, 255, 0.6);
}

/* ================================================= */
/* UNIT */
/* ================================================= */

.nrdb-ui-text-value span {
  font-size: clamp(0.8rem, 2.5vw, 1.1rem);
  margin-left: 4px;
  color: var(--text-muted);
}

/* ================================================= */
/* STATUS COLORS */
/* ================================================= */

.ff-ok {
  color: var(--accent-green) !important;
}

.ff-warn {
  color: var(--accent-amber) !important;
}

.ff-alert {
  color: var(--accent-red) !important;
}

.ff-muted {
  color: var(--text-muted) !important;
}

/* ================================================= */
/* COMPACT MODE */
/* ================================================= */

.nrdb-ui-widget[data-compact="true"] .nrdb-ui-text-value {
  font-size: clamp(1.1rem, 4vw, 1.6rem) !important;
}

