// Helper functions
function clamp(val, min, max) {
    return Math.min(Math.max(val, min), max);
}

function vary(prev, min, max, step = 0.5) {
    const delta = (Math.random() * 2 - 1) * step;
    return clamp(prev + delta, min, max);
}

// Load previous values or initialize
let state = context.get("state") || {
    temp: 24.0,       // °C
    humidity: 45.0,   // %
    co2: 600,         // ppm
    nox: 20,          // ppb
    voc: 150,         // ppb
    pm1: 5.0,         // µg/m³
    pm2_5: 8.0,       // µg/m³
    pm4: 10.0,        // µg/m³
    pm10: 15.0        // µg/m³
};

// Apply small realistic variations
state.temp     = vary(state.temp, 21, 27, 0.2);
state.humidity = vary(state.humidity, 35, 60, 0.5);
state.co2      = vary(state.co2, 450, 1200, 20);
state.nox      = vary(state.nox, 5, 80, 3);
state.voc      = vary(state.voc, 80, 400, 10);
state.pm1      = vary(state.pm1, 0, 20, 0.5);
state.pm2_5    = vary(state.pm2_5, 0, 35, 0.7);
state.pm4      = vary(state.pm4, 0, 50, 1);
state.pm10     = vary(state.pm10, 0, 75, 1.5);

// Save state
context.set("state", state);

// Output payload
msg.payload = {
    timestamp: new Date().toISOString(),
    temp: Number(state.temp.toFixed(1)),
    humidity: Number(state.humidity.toFixed(1)),
    co2: Math.round(state.co2),
    nox: Math.round(state.nox),
    voc: Math.round(state.voc),
    pm1: Number(state.pm1.toFixed(1)),
    pm2_5: Number(state.pm2_5.toFixed(1)),
    pm4: Number(state.pm4.toFixed(1)),
    pm10: Number(state.pm10.toFixed(1))
};

return msg;

